const _hoisted_1 = /* @__PURE__ */ createStaticVNode('<h1 id="拉取代码" tabindex="-1">拉取代码 <a class="header-anchor" href="#拉取代码" aria-hidden="true">#</a></h1><p>git分为本地仓库和远程仓库，一般情况都是写完代码，commit到本地仓库（生成本地仓的commit ID，代表当前提交代码的版本号），然后push到远程仓库（记录这个版本号）</p><p>我们本地的git文件夹里面对应也存储了git本地仓库maste</p><h2 id="git-pull-rebase" tabindex="-1">git pull --rebase <a class="header-anchor" href="#git-pull-rebase" aria-hidden="true">#</a></h2><p>在多人使用同一个远程分支合作开发的时候，很可能出现push代码的时候出现以下问题：</p><div class="language-sh"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#FFCB6B;">To</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">https://github.com/zqy233/git.git</span></span>\n<span class="line"><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">!</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">[</span><span style="color:#A6ACCD;">rejected</span><span style="color:#89DDFF;">]</span><span style="color:#A6ACCD;">        </span><span style="color:#FFCB6B;">main</span><span style="color:#A6ACCD;"> -</span><span style="color:#89DDFF;">&gt;</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">main</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">(</span><span style="color:#FFCB6B;">fetch</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">first</span><span style="color:#89DDFF;">)</span></span>\n<span class="line"><span style="color:#FFCB6B;">error:</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">failed</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">to</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">push</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">some</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">refs</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">to</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">https://github.com/zqy233/git.git</span><span style="color:#89DDFF;">&#39;</span></span>\n<span class="line"><span style="color:#FFCB6B;">hint:</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">Updates</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">were</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">rejected</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">because</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">the</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">remote</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">contains</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">work</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">that</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">you</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">do</span></span>\n<span class="line"><span style="color:#FFCB6B;">hint:</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">not</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">have</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">locally.</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">This</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">is</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">usually</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">caused</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">by</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">another</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">repository</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">pushing</span></span>\n<span class="line"><span style="color:#FFCB6B;">hint:</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">to</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">the</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">same</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">ref.</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">You</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">may</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">want</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">to</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">first</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">integrate</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">the</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">remote</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">changes</span></span>\n<span class="line"><span style="color:#FFCB6B;">hint:</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">(</span><span style="color:#FFCB6B;">e.g.,</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">git pull ...</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">)</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">before</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">pushing</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">again.</span></span>\n<span class="line"><span style="color:#FFCB6B;">hint:</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">See</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">the</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">Note about fast-forwards</span><span style="color:#89DDFF;">&#39;</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">in</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">git push --help</span><span style="color:#89DDFF;">&#39;</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">for</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">details.</span></span>\n<span class="line"></span></code></pre></div><p>很明显此时远程分支有新的 commit 未同步到本地，无法推送。正常情况下执行<code>git pull</code>，再push代码即可</p><p>但这时<code>git log</code>会多出了一条 merge commit，这个 commit 就是在执行 <code>git pull</code> 的时候自动生成的。如果多人多次如此操作，那么提交记录就会出现很多条这种自动生成的 merge commit，非常难看 要解决以上问题，不再出现自动生成的 merge commit，那么只要在执行 <code>git pull</code> 的时候带上 <code>--rebase</code> 即可</p><h3 id="注意事项" tabindex="-1">注意事项 <a class="header-anchor" href="#注意事项" aria-hidden="true">#</a></h3><ul><li><strong>执行 <code>git pull --rebase</code>的时候必须保持本地目录干净。</strong> 即：不能存在状态为 <code>modified</code> 的文件。（存在<code>Untracked files</code>是没关系的）</li><li><strong>如果出现冲突，可以选择手动解决冲突后继续<code>rebase</code>，也可以放弃本次<code>rebase</code></strong></li></ul><h4 id="执行-git-pull-rebase-的时候必须保持本地目录干净" tabindex="-1">执行 git pull --rebase 的时候必须保持本地目录干净 <a class="header-anchor" href="#执行-git-pull-rebase-的时候必须保持本地目录干净" aria-hidden="true">#</a></h4><p><strong>1.</strong> 有 modified 状态的文件</p><p>本地有受版本控制的文件改动的时候，执行<code>git pull --rebase</code></p><div class="language-sh"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#FFCB6B;">error:</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">cannot</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">pull</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">with</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">rebase:</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">You</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">have</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">unstaged</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">changes.</span></span>\n<span class="line"><span style="color:#FFCB6B;">error:</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">please</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">commit</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">or</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">stash</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">them.</span></span>\n<span class="line"></span></code></pre></div><p>会出现以上报错，无法操作</p><p>就是因为本地有文件改动尚未提交造成的。此时有两种做法</p><ul><li><strong>如果本次修改已经完成，则可以先提交（commit）一下</strong></li><li><strong>如果本次修改尚未完成，则可以先贮藏：git stash</strong></li></ul><p>做了以上一种操作之后再尝试 <code>git pull --rebase</code>，不会再报错。 如果做了 <code>git stash</code> 操作，此时可以通过 <code>git stash pop</code> 回到之前的工作状态</p><p><code>git pull --rebase</code>如果出现冲突，可以选择手动解决冲突后继续 rebase，也可以放弃本次 rebase</p><div class="language-sh"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#676E95;font-style:italic;"># 解决冲突后使用</span></span>\n<span class="line"><span style="color:#FFCB6B;">git</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">rebase</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">--continue</span></span>\n<span class="line"><span style="color:#676E95;font-style:italic;"># 或者放弃本次rebase</span></span>\n<span class="line"><span style="color:#FFCB6B;">git</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">rebase</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">--abort</span></span>\n<span class="line"></span></code></pre></div><h3 id="总结" tabindex="-1">总结 <a class="header-anchor" href="#总结" aria-hidden="true">#</a></h3><p>多人基于同一个远程分支开发的时候，如果想要顺利 push 又不自动生成 merge commit，建议在每次提交都按照如下顺序操作</p><div class="language-sh"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#FFCB6B;">git</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">stash</span></span>\n<span class="line"><span style="color:#FFCB6B;">git</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">pull</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">--rebase</span></span>\n<span class="line"><span style="color:#FFCB6B;">git</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">push</span></span>\n<span class="line"><span style="color:#FFCB6B;">git</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">stash</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">pop</span></span>\n<span class="line"></span></code></pre></div><h2 id="git-reset回退" tabindex="-1">git reset回退 <a class="header-anchor" href="#git-reset回退" aria-hidden="true">#</a></h2><blockquote><p>git reset 命令用于回退版本，可以指定退回某一次提交的版本</p></blockquote><p>命令语法格式如下：</p><div class="language-sh"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#FFCB6B;">git</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">reset</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">[</span><span style="color:#A6ACCD;">--soft </span><span style="color:#89DDFF;">|</span><span style="color:#A6ACCD;"> --mixed </span><span style="color:#89DDFF;">|</span><span style="color:#A6ACCD;"> --hard</span><span style="color:#89DDFF;">]</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">[</span><span style="color:#A6ACCD;">HEAD</span><span style="color:#89DDFF;">]</span></span>\n<span class="line"></span></code></pre></div><h3 id="mixed" tabindex="-1"><strong>--mixed</strong> <a class="header-anchor" href="#mixed" aria-hidden="true">#</a></h3><p>默认，可以不用带该参数，用于重置暂存区的文件与上一次的提交(commit)保持一致，工作区文件内容保持不变。</p><div class="language-sh"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#FFCB6B;">git</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">reset</span><span style="color:#A6ACCD;">  </span><span style="color:#89DDFF;">[</span><span style="color:#A6ACCD;">HEAD</span><span style="color:#89DDFF;">]</span><span style="color:#A6ACCD;"> </span></span>\n<span class="line"></span></code></pre></div><p>实例：</p><div class="language-sh"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#FFCB6B;">git</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">reset</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">HEAD^</span><span style="color:#A6ACCD;">            </span><span style="color:#676E95;font-style:italic;"># 回退所有内容到上一个版本  </span></span>\n<span class="line"><span style="color:#FFCB6B;">git</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">reset</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">HEAD^</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">hello.php</span><span style="color:#A6ACCD;">  </span><span style="color:#676E95;font-style:italic;"># 回退 hello.php 文件的版本到上一个版本  </span></span>\n<span class="line"><span style="color:#FFCB6B;">git</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">reset</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">052e</span><span style="color:#A6ACCD;">             </span><span style="color:#676E95;font-style:italic;"># 回退到指定版本</span></span>\n<span class="line"></span></code></pre></div><h3 id="soft" tabindex="-1"><strong>--soft</strong> <a class="header-anchor" href="#soft" aria-hidden="true">#</a></h3><p>用于回退到某个版本：</p><div class="language-sh"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#FFCB6B;">git</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">reset</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">--soft</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">HEAD~index</span></span>\n<span class="line"></span></code></pre></div><p>实例：</p><div class="language-sh"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#FFCB6B;">git</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">reset</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">--soft</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">HEAD~</span><span style="color:#F78C6C;">3</span><span style="color:#A6ACCD;">   </span><span style="color:#676E95;font-style:italic;"># 回退上上上一个版本 </span></span>\n<span class="line"></span></code></pre></div><h3 id="hard" tabindex="-1"><strong>--hard</strong> <a class="header-anchor" href="#hard" aria-hidden="true">#</a></h3><p>撤销工作区中所有未提交的修改内容，将暂存区与工作区都回到上一次版本，并删除之前的所有信息提交：</p><div class="language-sh"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#FFCB6B;">git</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">reset</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">--hard</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">HEAD</span></span>\n<span class="line"></span></code></pre></div><p>**注意：**谨慎使用 <strong>–-hard</strong> 参数，它会删除回退点之前的所有信息</p><p>实例：</p><div class="language-sh"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#FFCB6B;">git</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">reset</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">--hard</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">HEAD~</span><span style="color:#F78C6C;">3</span><span style="color:#A6ACCD;">  </span><span style="color:#676E95;font-style:italic;"># 回退上上上一个版本  </span></span>\n<span class="line"><span style="color:#FFCB6B;">git</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">reset</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">–hard</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">bae128</span><span style="color:#A6ACCD;">  </span><span style="color:#676E95;font-style:italic;"># 回退到某个版本回退点之前的所有信息。 </span></span>\n<span class="line"><span style="color:#FFCB6B;">git</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">reset</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">--hard</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">origin/master</span><span style="color:#A6ACCD;">    </span><span style="color:#676E95;font-style:italic;"># 将本地的状态回退到和远程的一样 </span></span>\n<span class="line"></span></code></pre></div><p><strong>HEAD 说明：</strong></p><ul><li>HEAD 表示当前版本</li><li>HEAD^ 上一个版本</li><li>HEAD^^ 上上一个版本</li><li>HEAD^^^ 上上上一个版本</li><li>以此类推...</li></ul><p>可以使用 ～数字表示</p><ul><li>HEAD~0 表示当前版本</li><li>HEAD~1 上一个版本</li><li>HEAD^2 上上一个版本</li><li>HEAD^3 上上上一个版本</li><li>以此类推...</li></ul>', 47);
